const body = $input.first().json.body || $input.first().json;
const type = String(body.type || '').trim();
const name = String(body.customerName || 'عميل').trim();
const title = String(body.title || 'عرض السعر').trim();
const total = body.totalAmount != null ? Number(body.totalAmount) : null;
const wo = body.workOrderId ? String(body.workOrderId) : '';

let message = '';
if (type === 'quote_approved') {
  message = `مرحباً ${name}،\nتم اعتماد عرض السعر: ${title}`;
  if (total != null && !Number.isNaN(total)) message += `\nالإجمالي: ${total} ج.م`;
  message += '\nسيتواصل معك فريقنا قريباً.';
} else if (type === 'quote_won') {
  message = `تهانينا ${name}!\nتم تأكيد موافقتكم على: ${title}`;
  if (wo) message += `\nمرجع أمر الشغل: ${wo}`;
} else {
  message = `إشعار نظام: ${type || 'unknown'}`;
}

return [{ json: { ok: true, type, customerName: name, title, message, raw: body } }];
